import{_ as e,o as l,c as o,ag as i}from"./chunks/framework-C5-Jzrz4.js";const a=JSON.parse('{"title":"核心模块功能详解","description":"启动流程、路由权限、状态管理、HTTP、国际化和偏好配置","frontmatter":{"title":"核心模块功能详解","description":"启动流程、路由权限、状态管理、HTTP、国际化和偏好配置"},"headers":[],"relativePath":"scripts/guide/04-核心模块功能详解.md","filePath":"scripts/guide/04-核心模块功能详解.md","lastUpdated":null}');const d=e({name:"scripts/guide/04-核心模块功能详解.md"},[["render",function(e,a,d,t,c,r){return l(),o("div",null,[...a[0]||(a[0]=[i('<h1 id="核心模块功能详解" tabindex="-1">核心模块功能详解 <a class="header-anchor" href="#核心模块功能详解" aria-label="Permalink to &quot;核心模块功能详解&quot;">​</a></h1><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>本文档聚焦主应用运行主链路：启动、路由、权限、状态、请求、国际化和偏好配置。</p><h2 id="适用范围" tabindex="-1">适用范围 <a class="header-anchor" href="#适用范围" aria-label="Permalink to &quot;适用范围&quot;">​</a></h2><ul><li>新功能接入前理解框架主流程</li><li>调试登录、路由、菜单、请求问题</li></ul><h2 id="对应源码目录或关键文件" tabindex="-1">对应源码目录或关键文件 <a class="header-anchor" href="#对应源码目录或关键文件" aria-label="Permalink to &quot;对应源码目录或关键文件&quot;">​</a></h2><ul><li><code>apps/web-antd/src/main.ts</code></li><li><code>apps/web-antd/src/bootstrap.ts</code></li><li><code>apps/web-antd/src/router/{index,guard,access}.ts</code></li><li><code>apps/web-antd/src/store/*</code></li><li><code>apps/web-antd/src/utils/http/*</code></li><li><code>apps/web-antd/src/locales/index.ts</code></li><li><code>apps/web-antd/src/preferences.ts</code></li><li><code>apps/web-antd/src/adapter/{form,component}/</code></li></ul><h2 id="核心机制或功能说明" tabindex="-1">核心机制或功能说明 <a class="header-anchor" href="#核心机制或功能说明" aria-label="Permalink to &quot;核心机制或功能说明&quot;">​</a></h2><h3 id="启动流程" tabindex="-1">启动流程 <a class="header-anchor" href="#启动流程" aria-label="Permalink to &quot;启动流程&quot;">​</a></h3><p><code>main.ts</code>：<code>initPreferences()</code> -&gt; 动态导入 <code>bootstrap()</code> -&gt; <code>unmountGlobalLoading()</code></p><p><code>bootstrap.ts</code> 关键步骤：</p><ol><li>初始化组件适配器 <code>initComponentAdapter</code></li><li>初始化表单适配 <code>initSetupVbenForm</code></li><li>设置弹窗默认参数 <code>setDefaultModalProps</code></li><li>注册全局组件和 <code>v-loading</code></li><li>初始化 i18n 与 Pinia</li><li>注册权限指令 <code>v-access</code></li><li>初始化 <code>tippy</code></li><li>安装路由与守卫</li><li>安装 Motion 插件</li><li>监听路由动态更新标题</li></ol><h3 id="路由与权限" tabindex="-1">路由与权限 <a class="header-anchor" href="#路由与权限" aria-label="Permalink to &quot;路由与权限&quot;">​</a></h3><ul><li>路由实例：<code>router/index.ts</code></li><li>核心路由：<code>router/routes/core.ts</code></li><li>守卫：<code>router/guard.ts</code><ul><li><code>setupCommonGuard</code>：进度条和已加载路径</li><li><code>setupAccessGuard</code>：token 检查、动态路由生成</li></ul></li><li>后端菜单转换：<code>router/access.ts</code><ul><li><code>Layout -&gt; BasicLayout</code></li><li><code>ParentView -&gt; &#39;&#39;</code></li><li><code>InnerLink + link -&gt; IFrameView</code></li><li>支持 <code>RootMenu</code>、外链、内嵌和 query 处理</li></ul></li></ul><h3 id="状态管理" tabindex="-1">状态管理 <a class="header-anchor" href="#状态管理" aria-label="Permalink to &quot;状态管理&quot;">​</a></h3><ul><li>应用层：<code>apps/web-antd/src/store</code><ul><li><code>useAuthStore</code>：登录、登出、用户信息</li><li><code>useDictStore</code>：字典缓存和请求去重</li><li><code>useNotifyStore</code>：SSE 通知</li><li><code>useTenantStore</code>：租户列表和选中态</li></ul></li><li>框架层：<code>@vben/stores</code></li></ul><h3 id="http-封装" tabindex="-1">HTTP 封装 <a class="header-anchor" href="#http-封装" aria-label="Permalink to &quot;HTTP 封装&quot;">​</a></h3><ul><li>入口：<code>utils/http/index.ts</code></li><li>请求库：<code>alova + axios adapter</code></li><li>默认能力： <ul><li>token、语言头、<code>ClientID</code></li><li>GET/DELETE 参数序列化 <code>arrayFormat: repeat</code></li><li>业务码 200 成功分支</li><li>401 统一登出</li><li>可选请求/响应加解密（RSA + AES）</li><li><code>getWithMsg/postWithMsg/putWithMsg/deleteWithMsg</code></li></ul></li></ul><h3 id="国际化" tabindex="-1">国际化 <a class="header-anchor" href="#国际化" aria-label="Permalink to &quot;国际化&quot;">​</a></h3><ul><li>入口：<code>locales/index.ts</code></li><li>应用语言包：<code>locales/langs/{zh-CN,en-US}</code></li><li>同步三方语言：<code>antdv-next locale</code> 与 <code>dayjs.locale</code></li></ul><h3 id="偏好配置" tabindex="-1">偏好配置 <a class="header-anchor" href="#偏好配置" aria-label="Permalink to &quot;偏好配置&quot;">​</a></h3><ul><li>文件：<code>preferences.ts</code></li><li>当前覆盖重点： <ul><li><code>app.accessMode = &#39;mixed&#39;</code></li><li><code>app.enableRefreshToken = false</code></li><li><code>footer.enable = false</code></li><li><code>tabbar.persist = false</code></li><li>主题色与圆角</li></ul></li></ul><h2 id="使用方式、扩展方式或注意事项" tabindex="-1">使用方式、扩展方式或注意事项 <a class="header-anchor" href="#使用方式、扩展方式或注意事项" aria-label="Permalink to &quot;使用方式、扩展方式或注意事项&quot;">​</a></h2><ul><li>若新增表单组件，需同步更新 <code>adapter/component/index.ts</code> 与 <code>adapter/form.ts</code>。</li><li>若后端菜单字段变更，需先修改 <code>router/access.ts</code> 的映射规则。</li><li>若开启加密，建议先以 <code>POST/PUT + encrypt: true</code> 小范围验证。</li></ul>',24)])])}]]);export{a as __pageData,d as default};
